from dataclasses import dataclass, field
from typing import Literal

ChampionPhase = Literal["candidate", "enabled", "active", "sustaining", "at_risk"]

@dataclass
class ChangeChampion:
    name: str
    role: str
    team: str
    peer_credibility: int       # 1–5: do peers listen to this person?
    domain_expertise: int       # 1–5: deep understanding of the work being changed
    change_openness: int        # 1–5: personal comfort with new tools / ways of working
    communication_skill: int    # 1–5: ability to explain, demonstrate, reassure
    capacity_hours_per_week: float  # hours available for champion activities
    phase: ChampionPhase = "candidate"
    concerns: list[str] = field(default_factory=list)
    achievements: list[str] = field(default_factory=list)

    @property
    def suitability_score(self) -> float:
        return (
            self.peer_credibility  * 0.35 +
            self.domain_expertise  * 0.25 +
            self.change_openness   * 0.25 +
            self.communication_skill * 0.15
        )

    @property
    def capacity_risk(self) -> str:
        if self.capacity_hours_per_week >= 4:
            return "LOW — sufficient for active champion role"
        if self.capacity_hours_per_week >= 2:
            return "MEDIUM — can handle pilot phase; may need support at scale"
        return "HIGH — insufficient capacity; risk of burnout or disengagement"

    def activation_readiness(self) -> bool:
        """Can this champion move to the active phase?"""
        return (
            self.phase == "enabled" and
            self.suitability_score >= 3.0 and
            self.capacity_hours_per_week >= 2.0
        )

    def summary(self) -> str:
        return (
            f"{self.name} ({self.role} / {self.team}) | "
            f"Suitability: {self.suitability_score:.2f}/5 | "
            f"Phase: {self.phase} | "
            f"Capacity risk: {self.capacity_risk}"
        )


@dataclass
class ChampionNetwork:
    use_case: str
    champions: list[ChangeChampion] = field(default_factory=list)

    def add(self, c: ChangeChampion) -> "ChampionNetwork":
        self.champions.append(c)
        return self

    def coverage_by_team(self) -> dict[str, int]:
        coverage = {}
        for c in self.champions:
            coverage[c.team] = coverage.get(c.team, 0) + 1
        return coverage

    def at_risk_champions(self) -> list[ChangeChampion]:
        return [c for c in self.champions
                if c.capacity_hours_per_week < 2 or c.suitability_score < 2.5]

    def ready_to_activate(self) -> list[ChangeChampion]:
        return [c for c in self.champions if c.activation_readiness()]

    def network_health(self) -> str:
        total = len(self.champions)
        at_risk = len(self.at_risk_champions())
        active = len([c for c in self.champions if c.phase == "active"])
        coverage = self.coverage_by_team()
        lines = [
            f"=== Champion Network: {self.use_case} ===",
            f"Total: {total} | Active: {active} | At risk: {at_risk}",
            f"Team coverage: {dict(coverage)}",
        ]
        uncovered = [t for t, n in coverage.items() if n == 0]
        if uncovered:
            lines.append(f"ALERT: No champion in teams: {uncovered}")
        if at_risk:
            lines.append(f"At-risk champions: {[c.name for c in self.at_risk_champions()]}")
        return "\n".join(lines)


# FNOL pilot champion network
network = ChampionNetwork("FNOL Auto-Classification Pilot")

network.add(ChangeChampion(
    "Priya Sharma", "Senior Claims Adjuster", "Motor Claims",
    peer_credibility=5, domain_expertise=5, change_openness=4, communication_skill=4,
    capacity_hours_per_week=3, phase="active",
    achievements=["Ran team demo of FNOL tool; 80% of team signed up for pilot"],
))
network.add(ChangeChampion(
    "Dan Osei", "Claims Team Lead", "Property Claims",
    peer_credibility=4, domain_expertise=4, change_openness=3, communication_skill=5,
    capacity_hours_per_week=4, phase="enabled",
    concerns=["Wants to see accuracy data before running team demo"],
))
network.add(ChangeChampion(
    "Lena Koch", "Junior Adjuster", "Liability Claims",
    peer_credibility=2, domain_expertise=3, change_openness=5, communication_skill=3,
    capacity_hours_per_week=1, phase="candidate",  # capacity too low
))

print(network.network_health())
print()
for c in network.champions:
    print(c.summary())
